import{_ as t,C as d,o as c,c as a,a7 as r,E as l}from"./chunks/framework.D3qk93i9.js";const S=JSON.parse('{"title":"固件烧录","description":"使用浏览器完成 OSRBOT 设备的在线烧录或恢复出厂。","frontmatter":{"title":"固件烧录","description":"使用浏览器完成 OSRBOT 设备的在线烧录或恢复出厂。"},"headers":[],"relativePath":"updater.md","filePath":"updater.md","lastUpdated":1781692298000}'),i={name:"updater.md"};function s(p,e,n,m,_,u){const o=d("FirmwareUpdater");return c(),a("div",null,[e[0]||(e[0]=r('<h1 id="固件烧录" tabindex="-1">固件烧录 <a class="header-anchor" href="#固件烧录" aria-label="Permalink to &quot;固件烧录&quot;">​</a></h1><blockquote><p>需要 Chrome 或 Edge 浏览器（支持 Web Serial API）。</p></blockquote><p>这个页面提供两种烧录方式：</p><ul><li><strong>在线烧录</strong>：设备正常开机时优先通过 <code>fw</code> 协议只更新 app 固件；如果设备已经在 ESP-ROM 下载模式，会自动刷写当前选择例程的 full flash 固件。远端固件可以直接从当前仓库例程中选择；自定义 URL 必须填写完整 HTTPS 地址。</li><li><strong>恢复出厂</strong>：第一次刷机、恢复出厂或固件无法启动时使用，需要进入 BOOT 下载模式并写入站内 full flash 固件。</li></ul><p>所有当前仓库例程都会内置 <code>fw</code> 更新协议。设备完成一次恢复出厂后，后续在这些例程之间切换可以直接使用在线烧录。</p><p>本地 <code>.bin</code> 文件仍可用于内部测试或临时固件验证。</p><details class="details custom-block"><summary>例程固件刷入后，建议测试流程</summary><ol><li>打开串口监视器，发送 <code>diag</code>，确认芯片 SN、Flash、Heap、I2C、IMU、地磁、SBUS 状态。</li><li>发送 <code>imu</code> 和 <code>mag</code>，轻微转动开发板，确认原始数据会变化。</li><li>发送 <code>ledtest</code> 和 <code>beeptest</code>，确认 LED 与蜂鸣器工作。</li><li>发送 <code>rc</code>，推动遥控器摇杆，确认通道数值变化。</li><li>架空车辆后发送 <code>servo left</code>、<code>servo center</code>、<code>servo right</code>，确认舵机方向。</li><li>架空车辆后发送 <code>motor fwd</code>、<code>motor rev</code>、<code>motor stop</code>，确认电机正反转。</li><li>架空车辆后发送 <code>drive on</code>，用遥控器 CH0/CH2 做受限低速测试；结束发送 <code>drive off</code>。</li></ol></details>',7)),l(o)])}const h=t(i,[["render",s]]);export{S as __pageData,h as default};
